><td>IGST</td><td class="right">{{ number_format((float)$invoice->igst_total,2) }}</td></tr><tr><td>Cess</td><td class="right">{{ number_format((float)$invoice->cess_total,2) }}</td></tr><tr class="total"><td>Invoice total</td><td class="right">{{ $invoice->currency }} {{ number_format((float)$invoice->grand_total,2) }}</td></tr><tr><td>Received amount</td><td class="right">{{ number_format((float)$invoice->amount_paid,2) }}</td></tr><tr class="total"><td>Current balance</td><td class="right">{{ number_format((float)$render['current_balance'],2) }}</td></tr></table></td></tr></table></div><div class="footer">{{ $invoice->company->name }} · {{ $invoice->invoice_number }} · Page <script type="text/php">if (isset($pdf)) { $pdf->page_text(520, 810, 'Page {PAGE_NUM} of {PAGE_COUNT}', null, 8, [0.4,0.4,0.4]); }</script></div></div></body></html>
